<template>
  <div>
    <el-card>
      <div slot="header" style="display:flex;justify-content:space-between;align-items:center">
        <span>课程管理</span>
        <el-button type="primary" size="small" @click="handleAdd">新增课程</el-button>
      </div>
      <el-form :inline="true" :model="query" size="small" style="margin-bottom:10px">
        <el-form-item label="课程名"><el-input v-model="query.name" placeholder="搜索" clearable /></el-form-item>
        <el-form-item><el-button type="primary" @click="loadData">搜索</el-button></el-form-item>
      </el-form>
      <el-table :data="list" border stripe v-loading="loading">
        <el-table-column prop="id" label="ID" width="60" />
        <el-table-column prop="name" label="课程名称" />
        <el-table-column prop="teacherName" label="授课教师" />
        <el-table-column prop="categoryName" label="分类" />
        <el-table-column prop="price" label="价格(元)" width="90" />
        <el-table-column prop="duration" label="时长(分钟)" width="90" />
        <el-table-column prop="maxStudents" label="最大人数" width="80" />
        <el-table-column prop="status" label="状态" width="80">
          <template slot-scope="scope">
            <el-tag :type="scope.row.status===1?'success':'info'" size="small">{{ scope.row.status===1?'上架':'下架' }}</el-tag>
          </template>
        </el-table-column>
        <el-table-column label="操作" width="168" align="center">
          <template slot-scope="scope">
            <div class="table-action-btns">
              <el-button size="mini" @click="handleEdit(scope.row)">编辑</el-button>
              <el-button size="mini" type="danger" @click="handleDel(scope.row)">删除</el-button>
            </div>
          </template>
        </el-table-column>
      </el-table>
      <el-pagination style="margin-top:15px;text-align:right" background layout="total, prev, pager, next"
        :total="total" :page-size="query.pageSize" :current-page.sync="query.pageNum" @current-change="loadData" />
    </el-card>
    <el-dialog :title="form.id?'编辑课程':'新增课程'" :visible.sync="dialogVisible" width="600px">
      <el-form :model="form" label-width="100px">
        <el-form-item label="课程名称"><el-input v-model="form.name" /></el-form-item>
        <el-form-item label="授课教师">
          <el-select v-model="form.teacherId" filterable placeholder="选择教师">
            <el-option v-for="t in teachers" :key="t.id" :label="t.name" :value="t.id" />
          </el-select>
        </el-form-item>
        <el-form-item label="分类">
          <el-select v-model="form.categoryId" placeholder="选择分类">
            <el-option v-for="c in categories" :key="c.id" :label="c.name" :value="c.id" />
          </el-select>
        </el-form-item>
        <el-form-item label="价格(元)"><el-input-number v-model="form.price" :min="0" :precision="2" /></el-form-item>
        <el-form-item label="时长(分钟)"><el-input-number v-model="form.duration" :min="15" :step="15" /></el-form-item>
        <el-form-item label="最大人数"><el-input-number v-model="form.maxStudents" :min="1" /></el-form-item>
        <el-form-item label="封面图">
          <el-upload action="/api/upload" :show-file-list="false" :on-success="(r)=>{form.coverImage=r.data}">
            <img v-if="form.coverImage" :src="form.coverImage" style="width:120px;height:80px;object-fit:cover">
            <el-button v-else size="small">上传图片</el-button>
          </el-upload>
        </el-form-item>
        <el-form-item label="课程描述"><el-input v-model="form.description" type="textarea" :rows="3" /></el-form-item>
        <el-form-item label="状态"><el-switch v-model="form.status" :active-value="1" :inactive-value="0" /></el-form-item>
      </el-form>
      <span slot="footer">
        <el-button @click="dialogVisible=false">取消</el-button>
        <el-button type="primary" @click="saveForm">确定</el-button>
      </span>
    </el-dialog>
  </div>
</template>
<script>
import request from '@/utils/request'
export default {
  data() {
    return {
      list: [], total: 0, loading: false, dialogVisible: false,
      query: { pageNum: 1, pageSize: 10, name: '' },
      form: {}, teachers: [], categories: []
    }
  },
  created() { this.loadData(); this.loadOptions() },
  methods: {
    loadData() {
      this.loading = true
      request.get('/api/course', { params: this.query }).then(res => {
        this.list = res.data.records; this.total = res.data.total
      }).finally(() => { this.loading = false })
    },
    loadOptions() {
      request.get('/api/user', { params: { pageNum: 1, pageSize: 999, role: 'TEACHER' } }).then(res => { this.teachers = res.data.records || [] })
      request.get('/api/category', { params: { pageNum: 1, pageSize: 999 } }).then(res => { this.categories = res.data.records || [] })
    },
    handleAdd() { this.form = { status: 1, maxStudents: 1, duration: 60, price: 0 }; this.dialogVisible = true },
    handleEdit(row) { this.form = { ...row }; this.dialogVisible = true },
    saveForm() {
      const api = this.form.id ? request.put('/api/course', this.form) : request.post('/api/course', this.form)
      api.then(() => { this.$message.success('操作成功'); this.dialogVisible = false; this.loadData() })
    },
    handleDel(row) {
      this.$confirm('确定删除该课程?', '提示', { type: 'warning' }).then(() => {
        request.delete('/api/course/' + row.id).then(() => { this.$message.success('删除成功'); this.loadData() })
      }).catch(() => {})
    }
  }
}
</script>
